const e = items[0].json;
const inv = e.data.object;
const issuedAt = new Date((inv.created || inv.status_transitions?.finalized_at) * 1000).toISOString();
const due = inv.due_date ? new Date(inv.due_date*1000).toISOString().slice(0,10) : null;
const amountRemaining = (inv.amount_remaining ?? inv.amount_due ?? 0) / 100;
return [{ json: { invoice_id: inv.id, issued_at: issuedAt, customer: inv.customer_name || inv.customer || 'Desconocido', amount_remaining: amountRemaining, due_date: due, customer_email: inv.customer_email || null, stripe_status: inv.status || e.type, event_type: e.type } }];
